function score(latency, tokens, entropy, baseline) {
  const zLat = (latency - baseline.latency.mean) / baseline.latency.std;
  const zTok = (tokens - baseline.tokens.mean) / baseline.tokens.std;
  const zEnt = (entropy - baseline.entropy.mean) / baseline.entropy.std;
  return Math.max(0, Math.abs(zLat) + Math.abs(zTok) + Math.abs(zEnt));
}
```

