function redactPrompt(prompt, tenantRules) {
  const patterns = Object.assign({}, defaultPIIPatterns, tenantRules?.patterns);
  let redacted = prompt;
  for (const key in patterns) {
    redacted = redacted.replace(patterns[key], '[REDACTED]');
  }
  return redacted;
}
