## Code Example

```javascript
// Minimal mutation code
type TenantPolicy = {
  tenantId: string
  maxTokens: number
  bannedTokens: string[]
  allowParaphrase: boolean
}
function tokenize(s: string): string[] { return s.split(/\s+/) }
function paraphrase(s: string): string { return s.replace(/transfer/g, 'move').replace(/\$/g, 'USD ') }
function applyMutation(prompt: string, policy: TenantPolicy): string {
  for (const t of policy.bannedTokens) {
    if (prompt.includes(t)) return prompt
  }
  let m = prompt
  if (policy.allowParaphrase) m = paraphrase(m)
  const tokens = tokenize(m)
  if (tokens.length > policy.maxTokens) m = tokens.slice(0, policy.maxTokens).join(' ')
  return m
}
```

